import { server, sse } from "@nifrajs/core"

const app = server()
// Your pub-sub of choice — subscribe returns an unsubscribe function.
declare const notifications: { subscribe(on: (n: { id: string }) => void): () => void }

// A live feed — push events until the client disconnects.
app.get("/notifications", (c) =>
  sse(c, (stream) => {
    const off = notifications.subscribe((n) =>
      stream.send({ event: "notification", id: n.id, data: JSON.stringify(n) }),
    )
    // Keep the connection open until the client leaves, then tear down.
    return new Promise<void>((resolve) =>
      stream.signal.addEventListener("abort", () => { off(); resolve() }, { once: true }),
    )
  }, { keepAlive: 15_000 }),
)

// secrets.ts — pure server logic: a secret constant, no `node:` import to catch.
import "@nifrajs/web/server-only"             // ← fails the CLIENT build (loud, with the import chain)
import type { ServerOnly } from "@nifrajs/web" // ← type-level intent: this value is server-only

// `ServerOnly<string>` is structurally `string` (the brand is an optional phantom field), so it
// stays assignment-compatible — it documents intent without obstructing real use.
